# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory backend for a team collaboration platform. It manages
users, projects, tasks, threaded messages with attachments, a performance
dashboard (completion rates, completion times, peer ratings) and exportable
reports (CSV / PDF).

Design notes
------------
* A single shared re-entrant lock guards all mutable state. Every store exposes
  that same lock instance via ``_lock`` so callers can reason about a single
  critical section across the whole manager.
* Entity ids are drawn from one global, monotonically increasing counter, so an
  id uniquely identifies an object regardless of its type. Ids start at 1.
* All public getters return deep copies, so mutating a returned object (or a
  returned list) can never corrupt the internal store.

The module is organised as a set of focused "stores" (users, projects, tasks,
messages, performance, reports) that share state through the owning
``TeamCollaborationManager``. This keeps each concern isolated while still
presenting a single, flat public API on the manager.

Development process: created, revised for full edge-case coverage, then
optimised for index-based lookups and minimal lock contention.
"""

from __future__ import annotations

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Any, Callable, Dict, List, Optional, Tuple


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    """Authorisation roles for a user."""

    ADMIN = "admin"
    MANAGER = "manager"
    MEMBER = "member"
    VIEWER = "viewer"


class ReportFormat(Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Identifies the kind of report payload produced."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all errors raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# Sentinel marking "argument not supplied" for partial updates.
_UNSET = object()


# ---------------------------------------------------------------------------
# Data model
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """File metadata attached to a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime
    data: bytes = b""


@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole = UserRole.MEMBER
    created_at: Optional[datetime] = None


@dataclass
class Project:
    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    description: str = ""
    created_at: Optional[datetime] = None


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus = TaskStatus.NOT_STARTED
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    description: str = ""
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# ---------------------------------------------------------------------------
# Store base
# ---------------------------------------------------------------------------
class _BaseStore:
    """Common behaviour shared by every store.

    All stores share the owning manager's lock and global id allocator so that
    cross-store operations remain atomic under a single critical section.
    """

    def __init__(self, manager: "TeamCollaborationManager") -> None:
        self._mgr = manager
        self._lock = manager._lock

    def _now(self) -> datetime:
        return self._mgr._now()

    def _next_id(self) -> int:
        return self._mgr._next_id()

    @staticmethod
    def _copy(obj: Any) -> Any:
        return copy.deepcopy(obj)


# ---------------------------------------------------------------------------
# Users
# ---------------------------------------------------------------------------
class UserStore(_BaseStore):
    def __init__(self, manager: "TeamCollaborationManager") -> None:
        super().__init__(manager)
        self.records: Dict[int, User] = {}
        self.by_username: Dict[str, int] = {}
        self.by_email: Dict[str, int] = {}

    # -- internal helpers --------------------------------------------------
    def _get(self, user_id: int) -> User:
        user = self.records.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    @staticmethod
    def _clean_username(username: Any) -> str:
        if username is None or not str(username).strip():
            raise ValidationError("username must be a non-empty string")
        return str(username).strip()

    @staticmethod
    def _clean_email(email: Any) -> str:
        if email is None:
            raise ValidationError("email must be a non-empty string")
        cleaned = str(email).strip()
        if not cleaned or "@" not in cleaned:
            raise ValidationError("email must be a non-empty string containing '@'")
        return cleaned

    # -- public API --------------------------------------------------------
    def register(self, username: str, email: str, role: UserRole = UserRole.MEMBER) -> User:
        with self._lock:
            username = self._clean_username(username)
            email = self._clean_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if username in self.by_username:
                raise DuplicateError("username already exists")
            if email in self.by_email:
                raise DuplicateError("email already exists")
            user = User(
                id=self._next_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._now(),
            )
            self.records[user.id] = user
            self.by_username[username] = user.id
            self.by_email[email] = user.id
            return self._copy(user)

    def get(self, user_id: int) -> User:
        with self._lock:
            return self._copy(self._get(user_id))

    def list(self) -> List[User]:
        with self._lock:
            return [self._copy(self.records[i]) for i in sorted(self.records)]

    def update(self, user_id: int, username: Any = _UNSET, email: Any = _UNSET,
               role: Any = _UNSET) -> User:
        with self._lock:
            user = self._get(user_id)
            new_username = user.username
            new_email = user.email
            new_role = user.role

            if username is not _UNSET:
                new_username = self._clean_username(username)
                owner = self.by_username.get(new_username)
                if owner is not None and owner != user_id:
                    raise DuplicateError("username already exists")

            if email is not _UNSET:
                new_email = self._clean_email(email)
                owner = self.by_email.get(new_email)
                if owner is not None and owner != user_id:
                    raise DuplicateError("email already exists")

            if role is not _UNSET:
                if not isinstance(role, UserRole):
                    raise ValidationError("role must be a UserRole")
                new_role = role

            if username is not _UNSET and new_username != user.username:
                del self.by_username[user.username]
                self.by_username[new_username] = user_id
            if email is not _UNSET and new_email != user.email:
                del self.by_email[user.email]
                self.by_email[new_email] = user_id

            user.username = new_username
            user.email = new_email
            user.role = new_role
            return self._copy(user)

    def delete(self, user_id: int) -> None:
        with self._lock:
            user = self._get(user_id)

            for project in self._mgr.projects.records.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project and cannot be deleted")

            assigned = self._mgr.tasks.by_assignee.get(user_id, [])
            for task_id in assigned:
                task = self._mgr.tasks.records[task_id]
                if task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open tasks and cannot be deleted")

            # Detach the (completed) tasks left behind so no dangling index remains.
            for task_id in list(assigned):
                self._mgr.tasks.records[task_id].assignee_id = None
            self._mgr.tasks.by_assignee.pop(user_id, None)

            del self.records[user_id]
            self.by_username.pop(user.username, None)
            self.by_email.pop(user.email, None)


# ---------------------------------------------------------------------------
# Projects
# ---------------------------------------------------------------------------
class ProjectStore(_BaseStore):
    def __init__(self, manager: "TeamCollaborationManager") -> None:
        super().__init__(manager)
        self.records: Dict[int, Project] = {}

    def _get(self, project_id: int) -> Project:
        project = self.records.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def create(self, name: str, start_date: datetime, end_date: datetime,
               owner_id: int, description: str = "") -> Project:
        with self._lock:
            self._mgr.users._get(owner_id)
            if not name or not str(name).strip():
                raise ValidationError("project name must be a non-empty string")
            if end_date < start_date:
                raise ValidationError("end_date must not precede start_date")
            project = Project(
                id=self._next_id(),
                name=str(name).strip(),
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                description=description or "",
                created_at=self._now(),
            )
            self.records[project.id] = project
            return self._copy(project)

    def get(self, project_id: int) -> Project:
        with self._lock:
            return self._copy(self._get(project_id))

    def list(self) -> List[Project]:
        with self._lock:
            return [self._copy(self.records[i]) for i in sorted(self.records)]

    def update(self, project_id: int, name: Any = _UNSET, start_date: Any = _UNSET,
               end_date: Any = _UNSET, description: Any = _UNSET) -> Project:
        with self._lock:
            project = self._get(project_id)
            new_name = project.name
            new_start = project.start_date
            new_end = project.end_date
            new_desc = project.description

            if name is not _UNSET:
                if not name or not str(name).strip():
                    raise ValidationError("project name must be a non-empty string")
                new_name = str(name).strip()
            if start_date is not _UNSET:
                new_start = start_date
            if end_date is not _UNSET:
                new_end = end_date
            if description is not _UNSET:
                new_desc = description or ""

            if new_end < new_start:
                raise ValidationError("end_date must not precede start_date")

            project.name = new_name
            project.start_date = new_start
            project.end_date = new_end
            project.description = new_desc
            return self._copy(project)

    def delete(self, project_id: int) -> None:
        with self._lock:
            self._get(project_id)
            tasks = self._mgr.tasks
            messages = self._mgr.messages

            for task_id in list(tasks.by_project.get(project_id, [])):
                task = tasks.records.pop(task_id, None)
                if task is None:
                    continue
                if task.assignee_id is not None:
                    bucket = tasks.by_assignee.get(task.assignee_id)
                    if bucket and task_id in bucket:
                        bucket.remove(task_id)
                for message_id in list(messages.by_task.get(task_id, [])):
                    messages.records.pop(message_id, None)
                messages.by_task.pop(task_id, None)
            tasks.by_project.pop(project_id, None)

            for message_id in list(messages.by_project.get(project_id, [])):
                messages.records.pop(message_id, None)
            messages.by_project.pop(project_id, None)

            del self.records[project_id]


# ---------------------------------------------------------------------------
# Tasks
# ---------------------------------------------------------------------------
class TaskStore(_BaseStore):
    def __init__(self, manager: "TeamCollaborationManager") -> None:
        super().__init__(manager)
        self.records: Dict[int, Task] = {}
        self.by_project: Dict[int, List[int]] = {}
        self.by_assignee: Dict[int, List[int]] = {}

    def _get(self, task_id: int) -> Task:
        task = self.records.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def create(self, project_id: int, title: str, assignee_id: Optional[int] = None,
               deadline: Optional[datetime] = None, description: str = "") -> Task:
        with self._lock:
            project = self._mgr.projects._get(project_id)
            if not title or not str(title).strip():
                raise ValidationError("task title must be a non-empty string")
            if assignee_id is not None:
                self._mgr.users._get(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not precede project start")

            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=str(title).strip(),
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                description=description or "",
                created_at=self._now(),
            )
            self.records[task.id] = task
            self.by_project.setdefault(project_id, []).append(task.id)
            if assignee_id is not None:
                self.by_assignee.setdefault(assignee_id, []).append(task.id)
            return self._copy(task)

    def get(self, task_id: int) -> Task:
        with self._lock:
            return self._copy(self._get(task_id))

    def list_by_project(self, project_id: int) -> List[Task]:
        with self._lock:
            self._mgr.projects._get(project_id)
            ids = sorted(self.by_project.get(project_id, []))
            return [self._copy(self.records[i]) for i in ids]

    def list_by_assignee(self, assignee_id: int) -> List[Task]:
        with self._lock:
            self._mgr.users._get(assignee_id)
            ids = sorted(self.by_assignee.get(assignee_id, []))
            return [self._copy(self.records[i]) for i in ids]

    def _set_assignee(self, task_id: int, assignee_id: Optional[int]) -> Task:
        task = self._get(task_id)
        if assignee_id is not None:
            self._mgr.users._get(assignee_id)
        old = task.assignee_id
        if old == assignee_id:
            return task
        if old is not None:
            bucket = self.by_assignee.get(old)
            if bucket and task_id in bucket:
                bucket.remove(task_id)
        if assignee_id is not None:
            self.by_assignee.setdefault(assignee_id, []).append(task_id)
        task.assignee_id = assignee_id
        return task

    def assign(self, task_id: int, assignee_id: int) -> Task:
        with self._lock:
            return self._copy(self._set_assignee(task_id, assignee_id))

    def reassign(self, task_id: int, assignee_id: int) -> Task:
        with self._lock:
            return self._copy(self._set_assignee(task_id, assignee_id))

    def unassign(self, task_id: int) -> Task:
        with self._lock:
            return self._copy(self._set_assignee(task_id, None))

    def set_deadline(self, task_id: int, deadline: Optional[datetime]) -> Task:
        with self._lock:
            task = self._get(task_id)
            if deadline is not None:
                project = self._mgr.projects.records.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline must not precede project start")
            task.deadline = deadline
            return self._copy(task)

    def update_status(self, task_id: int, status: TaskStatus) -> Task:
        with self._lock:
            task = self._get(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            now = self._now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            task.status = status
            return self._copy(task)


# ---------------------------------------------------------------------------
# Messages
# ---------------------------------------------------------------------------
class MessageStore(_BaseStore):
    def __init__(self, manager: "TeamCollaborationManager") -> None:
        super().__init__(manager)
        self.records: Dict[int, Message] = {}
        self.by_project: Dict[int, List[int]] = {}
        self.by_task: Dict[int, List[int]] = {}

    def _get(self, message_id: int) -> Message:
        message = self.records.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    def _build_attachments(self, attachments: Optional[List[Tuple[str, bytes]]],
                           uploader_id: int) -> List[Attachment]:
        built: List[Attachment] = []
        if not attachments:
            return built
        now = self._now()
        for item in attachments:
            filename, data = item
            if not filename or not str(filename).strip():
                raise ValidationError("attachment filename must be non-empty")
            payload = b"" if data is None else bytes(data)
            built.append(Attachment(
                filename=str(filename),
                size=len(payload),
                uploaded_by=uploader_id,
                uploaded_at=now,
                data=payload,
            ))
        return built

    def post(self, author_id: int, body: str, project_id: Optional[int] = None,
             task_id: Optional[int] = None, parent_id: Optional[int] = None,
             attachments: Optional[List[Tuple[str, bytes]]] = None) -> Message:
        with self._lock:
            if (project_id is None) == (task_id is None):
                raise ValidationError("exactly one of project_id or task_id is required")
            self._mgr.users._get(author_id)
            if project_id is not None:
                self._mgr.projects._get(project_id)
            else:
                self._mgr.tasks._get(task_id)
            if parent_id is not None:
                self._get(parent_id)

            built = self._build_attachments(attachments, author_id)
            text = "" if body is None else body
            if not text.strip() and not built:
                raise ValidationError("message requires a body or at least one attachment")

            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body=text,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built,
                created_at=self._now(),
                edited_at=None,
            )
            self.records[message.id] = message
            if project_id is not None:
                self.by_project.setdefault(project_id, []).append(message.id)
            else:
                self.by_task.setdefault(task_id, []).append(message.id)
            return self._copy(message)

    def edit(self, message_id: int, editor_id: int, new_body: str) -> Message:
        with self._lock:
            message = self._get(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            text = "" if new_body is None else new_body
            if not text.strip() and not message.attachments:
                raise ValidationError("message requires a body or at least one attachment")
            message.body = text
            message.edited_at = self._now()
            return self._copy(message)

    def add_attachment(self, message_id: int, uploader_id: int, filename: str,
                       data: bytes) -> Message:
        with self._lock:
            message = self._get(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError("only the author may attach to a message")
            if not filename or not str(filename).strip():
                raise ValidationError("attachment filename must be non-empty")
            payload = b"" if data is None else bytes(data)
            message.attachments.append(Attachment(
                filename=str(filename),
                size=len(payload),
                uploaded_by=uploader_id,
                uploaded_at=self._now(),
                data=payload,
            ))
            return self._copy(message)

    def list_by_project(self, project_id: int) -> List[Message]:
        with self._lock:
            self._mgr.projects._get(project_id)
            ids = sorted(self.by_project.get(project_id, []))
            return [self._copy(self.records[i]) for i in ids]

    def list_by_task(self, task_id: int) -> List[Message]:
        with self._lock:
            self._mgr.tasks._get(task_id)
            ids = sorted(self.by_task.get(task_id, []))
            return [self._copy(self.records[i]) for i in ids]

    def delete(self, message_id: int, requester_id: int) -> None:
        with self._lock:
            message = self._get(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError("only the author may delete a message")
            if message.project_id is not None:
                bucket = self.by_project.get(message.project_id)
                if bucket and message_id in bucket:
                    bucket.remove(message_id)
            else:
                bucket = self.by_task.get(message.task_id)
                if bucket and message_id in bucket:
                    bucket.remove(message_id)
            del self.records[message_id]


# ---------------------------------------------------------------------------
# Performance dashboard
# ---------------------------------------------------------------------------
class PerformanceStore(_BaseStore):
    def __init__(self, manager: "TeamCollaborationManager") -> None:
        super().__init__(manager)
        self.records: Dict[int, Rating] = {}
        self.by_ratee: Dict[int, List[int]] = {}

    def _assignee_tasks(self, user_id: int) -> List[Task]:
        ids = self._mgr.tasks.by_assignee.get(user_id, [])
        return [self._mgr.tasks.records[i] for i in ids]

    def get_completion_rate(self, user_id: int) -> float:
        with self._lock:
            self._mgr.users._get(user_id)
            tasks = self._assignee_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id: int) -> Optional[float]:
        with self._lock:
            self._mgr.users._get(user_id)
            durations = self._completion_durations(self._assignee_tasks(user_id))
            if not durations:
                return None
            return sum(durations) / len(durations)

    @staticmethod
    def _completion_durations(tasks: List[Task]) -> List[float]:
        durations = []
        for task in tasks:
            if (task.status == TaskStatus.COMPLETED
                    and task.started_at is not None
                    and task.completed_at is not None):
                durations.append((task.completed_at - task.started_at).total_seconds())
        return durations

    def submit_rating(self, rater_id: int, ratee_id: int, score: int,
                      feedback: str = "", task_id: Optional[int] = None) -> Rating:
        with self._lock:
            self._mgr.users._get(rater_id)
            self._mgr.users._get(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer between 1 and 5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                self._mgr.tasks._get(task_id)
            rating = Rating(
                id=self._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._now(),
            )
            self.records[rating.id] = rating
            self.by_ratee.setdefault(ratee_id, []).append(rating.id)
            return self._copy(rating)

    def _rating_scores(self, user_id: int) -> List[int]:
        return [self.records[i].score for i in self.by_ratee.get(user_id, [])]

    def get_ratings_summary(self, user_id: int) -> Dict[str, Any]:
        with self._lock:
            self._mgr.users._get(user_id)
            ids = sorted(self.by_ratee.get(user_id, []))
            ratings = [self._copy(self.records[i]) for i in ids]
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count else 0.0
            return {"count": count, "average": average, "ratings": ratings}

    def get_user_dashboard(self, user_id: int) -> Dict[str, Any]:
        with self._lock:
            self._mgr.users._get(user_id)
            tasks = self._assignee_tasks(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            durations = self._completion_durations(tasks)
            avg_time = sum(durations) / len(durations) if durations else None
            scores = self._rating_scores(user_id)
            rating_count = len(scores)
            rating_average = sum(scores) / rating_count if rating_count else 0.0
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completed / total if total else 0.0,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }


# ---------------------------------------------------------------------------
# Reports
# ---------------------------------------------------------------------------
class ReportStore(_BaseStore):
    def project_progress_report(self, project_id: int) -> Dict[str, Any]:
        with self._lock:
            self._mgr.projects._get(project_id)
            tasks = [self._mgr.tasks.records[i]
                     for i in self._mgr.tasks.by_project.get(project_id, [])]
            total = len(tasks)
            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1
            completed = status_counts[TaskStatus.COMPLETED.value]
            now = self._now()
            overdue = sum(
                1 for t in tasks
                if t.deadline is not None
                and t.deadline < now
                and t.status != TaskStatus.COMPLETED
            )
            per_assignee: Dict[int, Dict[str, Any]] = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                stats = per_assignee.setdefault(
                    task.assignee_id, {"total": 0, "completed": 0}
                )
                stats["total"] += 1
                if task.status == TaskStatus.COMPLETED:
                    stats["completed"] += 1
            for stats in per_assignee.values():
                stats["completion_rate"] = (
                    stats["completed"] / stats["total"] if stats["total"] else 0.0
                )
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completed / total if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
                "generated_at": now,
            }

    def _user_stats(self, user_id: int, project_id: Optional[int]) -> Dict[str, Any]:
        tasks = [self._mgr.tasks.records[i]
                 for i in self._mgr.tasks.by_assignee.get(user_id, [])]
        if project_id is not None:
            tasks = [t for t in tasks if t.project_id == project_id]
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        durations = PerformanceStore._completion_durations(tasks)
        avg_time = sum(durations) / len(durations) if durations else None
        scores = [self._mgr.performance.records[i].score
                  for i in self._mgr.performance.by_ratee.get(user_id, [])]
        rating_count = len(scores)
        rating_average = sum(scores) / rating_count if rating_count else 0.0
        user = self._mgr.users.records.get(user_id)
        return {
            "user_id": user_id,
            "username": user.username if user else None,
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": completed / total if total else 0.0,
            "average_completion_time": avg_time,
            "rating_count": rating_count,
            "rating_average": rating_average,
        }

    def team_performance_report(self, project_id: Optional[int] = None) -> Dict[str, Any]:
        with self._lock:
            if project_id is not None:
                self._mgr.projects._get(project_id)
                user_ids = set()
                for task_id in self._mgr.tasks.by_project.get(project_id, []):
                    assignee = self._mgr.tasks.records[task_id].assignee_id
                    if assignee is not None:
                        user_ids.add(assignee)
            else:
                user_ids = {uid for uid, ids in self._mgr.tasks.by_assignee.items() if ids}
            rows = [self._user_stats(uid, project_id) for uid in sorted(user_ids)]
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
                "generated_at": self._now(),
            }

    def individual_performance_report(self, user_id: int) -> Dict[str, Any]:
        with self._lock:
            self._mgr.users._get(user_id)
            stats = self._user_stats(user_id, None)
            ids = sorted(self._mgr.tasks.by_assignee.get(user_id, []))
            tasks = [self._task_summary(self._mgr.tasks.records[i]) for i in ids]
            report = {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "tasks": tasks,
                "generated_at": self._now(),
            }
            report.update(stats)
            return report

    @staticmethod
    def _task_summary(task: Task) -> Dict[str, Any]:
        return {
            "id": task.id,
            "title": task.title,
            "status": task.status.value,
            "assignee_id": task.assignee_id,
            "deadline": task.deadline.isoformat() if task.deadline else None,
            "started_at": task.started_at.isoformat() if task.started_at else None,
            "completed_at": task.completed_at.isoformat() if task.completed_at else None,
        }

    # -- export ------------------------------------------------------------
    def export_report(self, report: Dict[str, Any], fmt: ReportFormat):
        if not isinstance(report, dict):
            raise ValidationError("report must be a dictionary")
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if fmt == ReportFormat.CSV:
            return self._to_csv(report)
        return self._to_pdf(report)

    @staticmethod
    def _scalar(value: Any) -> str:
        if isinstance(value, Enum):
            return str(value.value)
        if isinstance(value, datetime):
            return value.isoformat()
        return str(value)

    def _to_csv(self, report: Dict[str, Any]) -> str:
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        rows = report.get("rows")
        if isinstance(rows, list) and rows and all(isinstance(r, dict) for r in rows):
            headers: List[str] = []
            for row in rows:
                for key in row.keys():
                    if key not in headers:
                        headers.append(key)
            writer.writerow(headers)
            for row in rows:
                writer.writerow([self._scalar(row.get(h, "")) for h in headers])
        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                writer.writerow([key, self._scalar(value)])
        return buffer.getvalue()

    def _to_pdf(self, report: Dict[str, Any]) -> bytes:
        lines = [self._scalar(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            if key == "rows" and isinstance(value, list):
                lines.append("rows: {0}".format(len(value)))
            else:
                lines.append("{0}: {1}".format(key, self._scalar(value))[:200])
        return _build_pdf(lines)


# ---------------------------------------------------------------------------
# Minimal PDF rendering (standard library only)
# ---------------------------------------------------------------------------
def _pdf_escape(text: str) -> str:
    return text.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")


def _build_pdf(lines: List[str]) -> bytes:
    """Render *lines* into a minimal, well-formed single-page PDF document."""
    content_ops = ["BT", "/F1 12 Tf", "72 720 Td", "14 TL"]
    for index, line in enumerate(lines):
        escaped = _pdf_escape(str(line))
        if index == 0:
            content_ops.append("({0}) Tj".format(escaped))
        else:
            content_ops.append("T* ({0}) Tj".format(escaped))
    content_ops.append("ET")
    content = "\n".join(content_ops).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
        b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>",
        b"<< /Length " + str(len(content)).encode("ascii") + b" >>\nstream\n"
        + content + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    out = bytearray(b"%PDF-1.4\n")
    offsets: List[int] = []
    for number, body in enumerate(objects, start=1):
        offsets.append(len(out))
        out += str(number).encode("ascii") + b" 0 obj\n" + body + b"\nendobj\n"

    xref_pos = len(out)
    size = len(objects) + 1
    out += b"xref\n0 " + str(size).encode("ascii") + b"\n"
    out += b"0000000000 65535 f \n"
    for offset in offsets:
        out += "{0:010d} 00000 n \n".format(offset).encode("ascii")
    out += b"trailer\n<< /Size " + str(size).encode("ascii") + b" /Root 1 0 R >>\n"
    out += b"startxref\n" + str(xref_pos).encode("ascii") + b"\n%%EOF"
    return bytes(out)


# ---------------------------------------------------------------------------
# Manager facade
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Single, thread-safe entry point for the collaboration platform."""

    def __init__(self, now: Optional[Callable[[], datetime]] = None) -> None:
        self._lock = threading.RLock()
        self._now = now if now is not None else datetime.now
        self._id_counter = 0

        self.users = UserStore(self)
        self.projects = ProjectStore(self)
        self.tasks = TaskStore(self)
        self.messages = MessageStore(self)
        self.performance = PerformanceStore(self)
        self.reports = ReportStore(self)

    def _next_id(self) -> int:
        with self._lock:
            self._id_counter += 1
            return self._id_counter

    # -- users -------------------------------------------------------------
    def register_user(self, username: str, email: str,
                      role: UserRole = UserRole.MEMBER) -> User:
        return self.users.register(username, email, role)

    def get_user(self, user_id: int) -> User:
        return self.users.get(user_id)

    def list_users(self) -> List[User]:
        return self.users.list()

    def update_user(self, user_id: int, username: Any = _UNSET, email: Any = _UNSET,
                    role: Any = _UNSET) -> User:
        return self.users.update(user_id, username=username, email=email, role=role)

    def delete_user(self, user_id: int) -> None:
        return self.users.delete(user_id)

    # -- projects ----------------------------------------------------------
    def create_project(self, name: str, start_date: datetime, end_date: datetime,
                       owner_id: int, description: str = "") -> Project:
        return self.projects.create(name, start_date, end_date, owner_id, description)

    def get_project(self, project_id: int) -> Project:
        return self.projects.get(project_id)

    def list_projects(self) -> List[Project]:
        return self.projects.list()

    def update_project(self, project_id: int, name: Any = _UNSET,
                       start_date: Any = _UNSET, end_date: Any = _UNSET,
                       description: Any = _UNSET) -> Project:
        return self.projects.update(
            project_id, name=name, start_date=start_date,
            end_date=end_date, description=description,
        )

    def delete_project(self, project_id: int) -> None:
        return self.projects.delete(project_id)

    # -- tasks -------------------------------------------------------------
    def create_task(self, project_id: int, title: str, assignee_id: Optional[int] = None,
                    deadline: Optional[datetime] = None, description: str = "") -> Task:
        return self.tasks.create(project_id, title, assignee_id, deadline, description)

    def get_task(self, task_id: int) -> Task:
        return self.tasks.get(task_id)

    def list_tasks_by_project(self, project_id: int) -> List[Task]:
        return self.tasks.list_by_project(project_id)

    def list_tasks_by_assignee(self, assignee_id: int) -> List[Task]:
        return self.tasks.list_by_assignee(assignee_id)

    def assign_task(self, task_id: int, assignee_id: int) -> Task:
        return self.tasks.assign(task_id, assignee_id)

    def reassign_task(self, task_id: int, assignee_id: int) -> Task:
        return self.tasks.reassign(task_id, assignee_id)

    def unassign_task(self, task_id: int) -> Task:
        return self.tasks.unassign(task_id)

    def set_deadline(self, task_id: int, deadline: Optional[datetime]) -> Task:
        return self.tasks.set_deadline(task_id, deadline)

    def update_status(self, task_id: int, status: TaskStatus) -> Task:
        return self.tasks.update_status(task_id, status)

    # -- messaging ---------------------------------------------------------
    def post_message(self, author_id: int, body: str, project_id: Optional[int] = None,
                     task_id: Optional[int] = None, parent_id: Optional[int] = None,
                     attachments: Optional[List[Tuple[str, bytes]]] = None) -> Message:
        return self.messages.post(
            author_id, body, project_id=project_id, task_id=task_id,
            parent_id=parent_id, attachments=attachments,
        )

    def edit_message(self, message_id: int, editor_id: int, new_body: str) -> Message:
        return self.messages.edit(message_id, editor_id, new_body)

    def add_attachment(self, message_id: int, uploader_id: int, filename: str,
                       data: bytes) -> Message:
        return self.messages.add_attachment(message_id, uploader_id, filename, data)

    def list_messages_by_project(self, project_id: int) -> List[Message]:
        return self.messages.list_by_project(project_id)

    def list_messages_by_task(self, task_id: int) -> List[Message]:
        return self.messages.list_by_task(task_id)

    def delete_message(self, message_id: int, requester_id: int) -> None:
        return self.messages.delete(message_id, requester_id)

    # -- performance -------------------------------------------------------
    def get_completion_rate(self, user_id: int) -> float:
        return self.performance.get_completion_rate(user_id)

    def get_average_completion_time(self, user_id: int) -> Optional[float]:
        return self.performance.get_average_completion_time(user_id)

    def submit_rating(self, rater_id: int, ratee_id: int, score: int,
                      feedback: str = "", task_id: Optional[int] = None) -> Rating:
        return self.performance.submit_rating(rater_id, ratee_id, score, feedback, task_id)

    def get_ratings_summary(self, user_id: int) -> Dict[str, Any]:
        return self.performance.get_ratings_summary(user_id)

    def get_user_dashboard(self, user_id: int) -> Dict[str, Any]:
        return self.performance.get_user_dashboard(user_id)

    # -- reports -----------------------------------------------------------
    def project_progress_report(self, project_id: int) -> Dict[str, Any]:
        return self.reports.project_progress_report(project_id)

    def team_performance_report(self, project_id: Optional[int] = None) -> Dict[str, Any]:
        return self.reports.team_performance_report(project_id)

    def individual_performance_report(self, user_id: int) -> Dict[str, Any]:
        return self.reports.individual_performance_report(user_id)

    def export_report(self, report: Dict[str, Any], fmt: ReportFormat):
        return self.reports.export_report(report, fmt)


